INSERT OR REPLACE INTO sh_weekly_summary(period_key,period_start,period_end,sample_count,reliable_sample_count,listener_avg,listener_min,listener_max,stream_start,stream_end,stream_growth,member_start,member_end,member_growth,likes_max,distinct_tracks,primary_host,quality_score,quality_flags,updated_at)
SELECT w.period_key,w.period_start,w.period_end,w.sample_count,w.reliable_sample_count,w.listener_avg,w.listener_min,w.listener_max,w.stream_start,w.stream_end,CASE WHEN w.stream_start IS NOT NULL AND w.stream_end>=w.stream_start THEN w.stream_end-w.stream_start END,w.member_start,w.member_end,CASE WHEN w.member_start IS NOT NULL AND w.member_end IS NOT NULL THEN w.member_end-w.member_start END,w.likes_max,(SELECT distinct_tracks FROM sh_weekly_summary old WHERE old.period_key=w.period_key),(SELECT primary_host FROM sh_weekly_summary old WHERE old.period_key=w.period_key),1,'["utc_rebuild"]',unixepoch('now')*1000 FROM sh_weekly_metric_utc w WHERE w.sample_count>0;
